import socket
import json
import threading
import time

class GameState:
    def __init__(self):
        self.game_name = "My Awesome Game"
        self.map_name = "Dusty Canyon"
        self.max_players = 32
        self.players = []
        self.running_since = time.time()
        self.version = "1.0.0"

    def add_player(self, player_name, score=0):
        if len(self.players) < self.max_players:
            self.players.append({"name": player_name, "score": score})
            return True
        return False

    def remove_player(self, player_name):
        self.players = [p for p in self.players if p["name"] != player_name]

    def get_status(self):
        uptime_seconds = int(time.time() - self.running_since)
        uptime_string = f"{uptime_seconds // 3600}h {(uptime_seconds % 3600) // 60}m {uptime_seconds % 60}s"

        return {
            "game_name": self.game_name,
            "version": self.version,
            "map": self.map_name,
            "players_online": len(self.players),
            "max_players": self.max_players,
            "uptime": uptime_string,
            "player_list": self.players,
            "status_timestamp": time.time()
        }

class GameServer:
    def __init__(self, host='0.0.0.0', port=27015):
        self.host = host
        self.port = port
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.game_state = GameState()
        self.running = False
        print(f"Game server listening on UDP {self.host}:{self.port}")

        # Populate some initial players for testing
        self.game_state.add_player("PlayerOne", 1500)
        self.game_state.add_player("PlayerTwo", 1200)
        self.game_state.add_player("PlayerThree", 900)
        self.game_state.add_player("AI_Bot_Alpha", 500)
        self.game_state.add_player("AI_Bot_Beta", 450)

    def _handle_request(self, data, address):
        try:
            query = data.decode('utf-8').strip().lower()
            if query == "status":
                status_data = self.game_state.get_status()
                response = json.dumps(status_data).encode('utf-8')
                self.sock.sendto(response, address)
                print(f"Sent status response to {address} ({len(response)} bytes)")
            else:
                error_msg = "Unknown command. Send 'status' for game state."
                self.sock.sendto(error_msg.encode('utf-8'), address)
                print(f"Sent error response to {address} for query: {query}")
        except Exception as e:
            print(f"Error handling request from {address}: {e}")
            error_msg = f"Server error: {e}".encode('utf-8')
            self.sock.sendto(error_msg, address)

    def start(self):
        self.running = True
        while self.running:
            try:
                data, address = self.sock.recvfrom(65535)  # Max UDP packet size
                threading.Thread(target=self._handle_request, args=(data, address)).start()
            except socket.timeout:
                continue
            except Exception as e:
                if self.running:
                    print(f"Server error: {e}")
                break

    def stop(self):
        self.running = False
        self.sock.close()
        print("Game server stopped.")

if __name__ == '__main__':
    server = GameServer(port=27015) # You can change the port if needed
    try:
        server.start()
    except KeyboardInterrupt:
        server.stop()